def heap_replace(heap, new_element):
    if not heap:
        return heap
    heap.pop(0)
    heap.append(new_element)
    index = len(heap) - 1
    while index > 0:
        parent = (index - 1) // 2
        if heap[index] < heap[parent]:
            heap[index], heap[parent] = heap[parent], heap[index]
            index = parent
        else:
            break
    return heap

